import{_ as i,o as e,c as a,ai as n}from"./chunks/framework.ampVZV4B.js";const k=JSON.parse('{"title":"缓存常见问题（穿透、雪崩、击穿）","description":"","frontmatter":{},"headers":[],"relativePath":"redis/cache-issues.md","filePath":"redis/cache-issues.md"}'),t={name:"redis/cache-issues.md"};function r(l,s,o,h,d,g){return e(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="缓存常见问题-穿透、雪崩、击穿" tabindex="-1">缓存常见问题（穿透、雪崩、击穿） <a class="header-anchor" href="#缓存常见问题-穿透、雪崩、击穿" aria-label="Permalink to “缓存常见问题（穿透、雪崩、击穿）”">​</a></h1><hr><h3 id="❓-面试官-能详细讲讲什么是缓存穿透、缓存击穿、缓存雪崩吗-它们之间有什么区别-分别怎么解决" tabindex="-1">❓ 面试官：能详细讲讲什么是缓存穿透、缓存击穿、缓存雪崩吗？它们之间有什么区别，分别怎么解决？ <a class="header-anchor" href="#❓-面试官-能详细讲讲什么是缓存穿透、缓存击穿、缓存雪崩吗-它们之间有什么区别-分别怎么解决" aria-label="Permalink to “❓ 面试官：能详细讲讲什么是缓存穿透、缓存击穿、缓存雪崩吗？它们之间有什么区别，分别怎么解决？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong></p><ul><li><strong>穿透</strong>：查询了<strong>根本不存在</strong>的数据（黑客攻击），缓存和数据库都查不到，导致请求全打在 DB 上。</li><li><strong>击穿</strong>：查询了<strong>热点</strong>数据，但它刚好<strong>过期了</strong>，瞬间大量并发请求打在 DB 上。</li><li><strong>雪崩</strong>：<strong>大量</strong>缓存数据在<strong>同一时间</strong>过期，或者 Redis 直接宕机，导致所有请求全打在 DB 上。</li></ul><p><strong>📝 详细原理解析与解决方案：</strong></p><h4 id="_1-缓存穿透-cache-penetration" tabindex="-1">1. 缓存穿透（Cache Penetration） <a class="header-anchor" href="#_1-缓存穿透-cache-penetration" aria-label="Permalink to “1. 缓存穿透（Cache Penetration）”">​</a></h4><ul><li><strong>场景</strong>：黑客拿脚本疯狂请求 <code>id=-1</code> 或者 <code>id=一串乱码</code> 的商品详情接口。由于这数据在 Redis 肯定没有，就会去查 MySQL。MySQL 也没有，所以不会写入缓存。下次同样的恶意请求来，依然会穿透缓存直接打挂 MySQL。</li><li><strong>解决方案</strong>： <ol><li><strong>缓存空对象（最常用、最简单）</strong>：即使 MySQL 查不到数据，我也往 Redis 里存一个 <code>key=-1, value=&quot;null&quot;</code>，并设置个短点的过期时间（比如 5 分钟）。下次黑客再查 <code>-1</code>，Redis 直接返回空串，不再打 MySQL。</li><li><strong>布隆过滤器（Bloom Filter，适合海量数据）</strong>：在访问 Redis 之前加一层布隆过滤器，里面存放了所有存在的 ID。如果布隆过滤器说 ID 不存在，直接抛出异常，连 Redis 都懒得查。</li></ol></li></ul><h4 id="_2-缓存击穿-cache-breakdown" tabindex="-1">2. 缓存击穿（Cache Breakdown） <a class="header-anchor" href="#_2-缓存击穿-cache-breakdown" aria-label="Permalink to “2. 缓存击穿（Cache Breakdown）”">​</a></h4><ul><li><strong>场景</strong>：双十一零点，某款特价秒杀商品（绝对的热点数据 <code>id=10086</code>）的缓存刚好在那一秒钟过期了。就在这 1 秒内，有 10 万个并发请求查询这件商品。Redis 没查到，这 10 万个请求瞬间全部跑去 MySQL 查详情，MySQL 瞬间崩溃。</li><li><strong>解决方案</strong>： <ol><li><strong>互斥锁（Mutex Lock，常用）</strong>： 当在 Redis 查不到数据时，不要立刻去查数据库。而是让这 10 万个线程去<strong>抢分布式锁（如 Redisson 或 SETNX）</strong>。 只有一个线程能抢到锁，它去查 MySQL 并把结果写回 Redis。剩下 99999 个抢不到锁的线程，休眠 50 毫秒后重试（这时候 Redis 里已经有值了，直接返回）。</li><li><strong>逻辑过期（永不过期）</strong>： 不给热点数据的 Key 设置真正的过期时间（TTL）。而是在 Value 的 JSON 里加一个字段：<code>&quot;expireAt&quot;: 1690000000</code>。 所有线程查到数据后判断这个时间戳：如果已经过期，依然返回旧数据（脏读），但会在后台启动一个异步线程去 MySQL 查新数据并更新 Redis。</li></ol></li></ul><h4 id="_3-缓存雪崩-cache-avalanche" tabindex="-1">3. 缓存雪崩（Cache Avalanche） <a class="header-anchor" href="#_3-缓存雪崩-cache-avalanche" aria-label="Permalink to “3. 缓存雪崩（Cache Avalanche）”">​</a></h4><ul><li><strong>场景</strong>：你的定时任务在每天晚上 2 点把几十万个商品的缓存全部加载到 Redis，并<strong>统一设置了 24 小时过期</strong>。结果到了第二天晚上 2 点，这几十万个 Key 瞬间同时失效。如果有大量用户正在访问，就会导致严重的数据库雪崩。</li><li><strong>解决方案</strong>： <ol><li><strong>过期时间加随机值（最核心）</strong>： 在原有的过期时间上加一个 <code>1~5 分钟的随机数</code>。这样保证几十万个 Key 不会在同一秒失效，而是平滑地分散在 5 分钟内。<div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 错误做法</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">redis.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(key, value, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">24</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 正确做法</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">redis.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(key, value, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">24</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> +</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> RandomUtil.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">randomInt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">300</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">));</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li><li><strong>服务降级、限流、熔断</strong>： 如果是 Redis 节点挂了导致的雪崩，启用 Sentinel 降级或使用 Nacos/Sentinel 配置接口限流，保护 MySQL 不死。</li></ol></li></ul><hr><h3 id="❓-面试官-布隆过滤器到底是怎么工作的-如果它说这个数据存在-那一定存在吗-【中级】" tabindex="-1">❓ 面试官：布隆过滤器到底是怎么工作的？如果它说这个数据存在，那一定存在吗？【中级】 <a class="header-anchor" href="#❓-面试官-布隆过滤器到底是怎么工作的-如果它说这个数据存在-那一定存在吗-【中级】" aria-label="Permalink to “❓ 面试官：布隆过滤器到底是怎么工作的？如果它说这个数据存在，那一定存在吗？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 布隆过滤器说<strong>存在，不一定存在（有误判率）</strong>；但它说<strong>不存在，那就一定不存在</strong>。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>内部结构</strong>： <ul><li>布隆过滤器本质上是一个极长的 <strong>Bitmap（位数组）</strong>，里面只有 0 和 1。</li><li>当你要存入一个值（比如 <code>user_1</code>）时，它会使用多个（比如 3 个）不同的 Hash 函数对 <code>user_1</code> 进行计算，得到 3 个位置下标，然后把 Bitmap 里这 3 个位置的 0 改成 1。</li></ul></li><li><strong>为什么会误判（说存在但其实不存在）？</strong>： <ul><li>当查询 <code>user_1</code> 时，它用同样的 3 个 Hash 函数算一遍，如果发现这 3 个位置<strong>全都是 1</strong>，它就会告诉你存在。</li><li><strong>坑在这里</strong>：假如你存了 <code>user_2</code> 和 <code>user_3</code>，它们经过 Hash 后把某些位置改成了 1。此时你查询一个根本没存过的 <code>hacker_999</code>，极其倒霉的是，<code>hacker_999</code> 算出来的 3 个位置，恰好被 <code>user_2</code> 和 <code>user_3</code> 占据了！这就导致了<strong>哈希冲突带来的误判</strong>。</li></ul></li><li><strong>为什么一定不存在？</strong>： <ul><li>只要有任意一个 Hash 函数算出来的位上是 <code>0</code>，说明它绝对没被存入过，百分百肯定不存在。</li></ul></li></ol><p><strong>🌟 面试加分项（实战经验）：</strong> 面试官可能会问：&quot;如果我把 MySQL 里的某条商品记录删了，我能去布隆过滤器里把它也删了吗？&quot; <strong>绝杀回答</strong>： &quot;不能！传统的布隆过滤器<strong>只支持插入和查询，绝对不支持删除！</strong> 因为多个值可能会 Hash 映射到同一个位上（就是上面说的冲突）。如果你为了删除 <code>user_1</code>，强行把它的 3 个位置都清 0，那原本复用了这几个位置的 <code>user_2</code> 和 <code>user_3</code> 也跟着遭殃了，后续查询会直接判定它们也不存在了。 如果业务强依赖删除操作，必须改用稍微占内存多一点的<strong>布谷鸟过滤器（Cuckoo Filter）</strong>或者带计数器的 Counting Bloom Filter。&quot;</p>`,20)])])}const p=i(t,[["render",r]]);export{k as __pageData,p as default};
